INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fe262fbd-a26a-4dff-9c6b-5c593c72918a',
  '00000000-0000-0000-0000-000000000001',
  $escape$LlamaIndex HuggingFaceLLM — Wiring Tokenizers and Chat Templates Correctly$escape$,
  $escape$When loading a local HF model via `HuggingFaceLLM`, LlamaIndex does not auto-detect the model's chat template. If you skip wiring `messages_to_prompt`, LlamaIndex falls back to a generic formatter that breaks instruction-tuned models like Llama-3 or Mistral-Instruct — the model sees raw role strings instead of proper special tokens.

The fix: pull the tokenizer via `AutoTokenizer.from_pretrained`, then pass its `apply_chat_template` method as the formatter. Also set `context_window` explicitly to match the model's `max_position_embeddings` — LlamaIndex defaults to 3900, which silently truncates context on modern long-context models.

`generate_kwargs` is forwarded directly to HF's `generate()` call, so `temperature`, `do_sample`, and `repetition_penalty` all work without any wrapper. For embeddings, `HuggingFaceEmbedding` wraps sentence-transformers and respects `max_length` — set this to match your chunk size or pooling degrades silently on long passages. Only pass `trust_remote_code=True` for models that explicitly require it (e.g., Phi-3); standard Llama/BERT variants don't need it and it widens your attack surface.$escape$,
  $escape$from transformers import AutoTokenizer
from llama_index.llms.huggingface import HuggingFaceLLM
from llama_index.core import Settings

MODEL = "meta-llama/Llama-3.2-3B-Instruct"
tokenizer = AutoTokenizer.from_pretrained(MODEL)

def messages_to_prompt(messages):
    return tokenizer.apply_chat_template(
        [{"role": m.role, "content": m.content} for m in messages],
        tokenize=False,
        add_generation_prompt=True,
    )

Settings.llm = HuggingFaceLLM(
    model_name=MODEL,
    tokenizer_name=MODEL,
    context_window=131072,
    max_new_tokens=512,
    messages_to_prompt=messages_to_prompt,
    generate_kwargs={"temperature": 0.1, "do_sample": True},
)$escape$,
  $escape$python$escape$,
