INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3a930fba-9cdd-41ab-bb11-4930e6fdb2d1',
  '00000000-0000-0000-0000-000000000001',
  $escape$LlamaIndex RAG Pipeline — Chunking, Retrieval, and Reranking That Actually Works$escape$,
  $escape$LlamaIndex's default `SentenceSplitter(chunk_size=512, chunk_overlap=50)` handles most corpora well, but switch to `SemanticSplitterNodeParser` when document boundaries are semantically ambiguous — it uses your configured embed model to split at meaning shifts rather than token counts, producing denser, more coherent nodes.

For retrieval, never set `similarity_top_k` to 3 at query time. Fetch 10–20 candidates via `VectorIndexRetriever`, then collapse them with `SentenceTransformerRerank`. Bi-encoders score speed; cross-encoders score relevance by seeing the query and chunk together — stacking them eliminates the precision loss that kills naive top-k.

Wire it through `RetrieverQueryEngine(retriever=retriever, node_postprocessors=[reranker])`. The `node_postprocessors` list executes in order, so you can prepend a `MetadataReplacementPostProcessor` to swap small window chunks for their full parent context before reranking — this is the `SentenceWindowNodeParser` pattern and consistently outperforms fixed chunking on long-form technical documents. Set `window_size=3` as your starting point.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, Settings
from llama_index.core.node_parser import SentenceSplitter
from llama_index.core.retrievers import VectorIndexRetriever
from llama_index.core.query_engine import RetrieverQueryEngine
from llama_index.core.postprocessor import SentenceTransformerRerank
from llama_index.embeddings.huggingface import HuggingFaceEmbedding

Settings.embed_model = HuggingFaceEmbedding(model_name="BAAI/bge-small-en-v1.5")
splitter = SentenceSplitter(chunk_size=512, chunk_overlap=50)
index = VectorStoreIndex.from_documents(docs, transformations=[splitter])

retriever = VectorIndexRetriever(index=index, similarity_top_k=10)
reranker = SentenceTransformerRerank(model="cross-encoder/ms-marco-MiniLM-L-2-v2", top_n=3)
query_engine = RetrieverQueryEngine(retriever=retriever, node_postprocessors=[reranker])

response = query_engine.query("How does attention work in transformers?")$escape$,
  $escape$python$escape$,
