INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2ce214e4-002c-4463-a61d-3e588e3e2e89',
  '00000000-0000-0000-0000-000000000001',
  $escape$LlamaIndex + Ollama — Private, Local RAG Without an API Key$escape$,
  $escape$LlamaIndex's `Ollama` LLM class and `OllamaEmbedding` let you build fully local RAG pipelines — no OpenAI key, no data leaving your machine. Swap `Settings.llm` and `Settings.embed_model` to point at a locally running Ollama server, and the rest of your LlamaIndex pipeline stays untouched.

Ollama's model library covers `llama3.2`, `mistral`, `codellama`, `nomic-embed-text`, and dozens more — pull them with `ollama pull <model>` and they're immediately available to LlamaIndex. `OllamaEmbedding` is critical here: using a cloud LLM with a cloud embedder still leaks your document corpus. Going fully local with both means sensitive codebases, internal docs, or PII-heavy datasets never touch a third-party API.

Set `request_timeout` on the `Ollama` constructor for long-context models that need extra inference time. For production-like local setups, `base_url` lets you point at a remote Ollama instance on your homelab or air-gapped server — same API, same LlamaIndex code.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, SimpleDirectoryReader, Settings
from llama_index.llms.ollama import Ollama
from llama_index.embeddings.ollama import OllamaEmbedding

Settings.llm = Ollama(model="llama3.2", request_timeout=120.0)
Settings.embed_model = OllamaEmbedding(
    model_name="nomic-embed-text",
    base_url="http://localhost:11434",
)

docs = SimpleDirectoryReader("./private_docs").load_data()
index = VectorStoreIndex.from_documents(docs)

response = index.as_query_engine().query(
    "Summarize the key architectural decisions."
)
print(response)$escape$,
