INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a0d42a9d-8dc5-40e3-909d-15f0595e72a7',
  '00000000-0000-0000-0000-000000000001',
  $escape$LlamaIndex Embeddings — Swapping Models and Catching the Dimension Footgun$escape$,
  $escape$LlamaIndex abstracts every embedding provider behind a unified `BaseEmbedding` interface. Set `Settings.embed_model` once and every `VectorStoreIndex`, retriever, and reranker picks it up — no per-index wiring needed. `text-embedding-3-small` (1536-dim) gives strong OpenAI quality; `BAAI/bge-small-en-v1.5` (384-dim) runs locally at ~40 ms/call with competitive MTEB recall scores. Always call `get_text_embedding_batch()` instead of looping `get_text_embedding()` — it respects `embed_batch_size` and parallelizes API calls automatically. For semantic similarity, cosine over the raw float vectors is the right primitive: BGE scores semantically close sentences at >0.85, OpenAI at >0.90. The critical footgun: dimension mismatch between index-time and query-time models is silent until retrieval — LlamaIndex won't error when you index with 1536-dim and query with 384-dim, it just returns garbage rankings. Lock `Settings.embed_model` before calling `from_documents()` and never reassign it mid-session without rebuilding the index.$escape$,
  $escape$from llama_index.embeddings.openai import OpenAIEmbedding
from llama_index.embeddings.huggingface import HuggingFaceEmbedding
from llama_index.core import Settings
import numpy as np

# Pin model before indexing — changing it later silently breaks retrieval
Settings.embed_model = HuggingFaceEmbedding(
    model_name="BAAI/bge-small-en-v1.5",
    embed_batch_size=32,
)

texts = ["LlamaIndex ingests documents", "LlamaIndex parses and indexes nodes"]
vecs = Settings.embed_model.get_text_embedding_batch(texts, show_progress=True)

a, b = np.array(vecs[0]), np.array(vecs[1])
print(f"dim={len(a)}, sim={np.dot(a,b)/(np.linalg.norm(a)*np.linalg.norm(b)):.4f}")$escape$,
  $escape$python$escape$,
