INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '29c0b7d3-f07a-4c5f-be42-0d076add4397',
  '00000000-0000-0000-0000-000000000001',
  $escape$LlamaIndex Streaming — Token-by-Token Output with StreamingResponse$escape$,
  $escape$LlamaIndex's default `query_engine.query()` blocks until the full response is ready — bad UX for long LLM outputs. Flip to streaming by passing `streaming=True` to `as_query_engine()`. This returns a `StreamingResponse` instead of a `Response`, exposing a `.response_gen` generator that yields tokens as the model produces them.

For chat use cases, `ChatEngine.stream_chat()` returns a `StreamingAgentChatResponse` with the same `.response_gen` interface. Both objects also expose `async_response_gen()` for async contexts — critical when serving multiple users concurrently in a FastAPI or async framework.

Avoid calling `.response` on a `StreamingResponse` before consuming the generator — it forces a full buffer flush and defeats streaming. Use `print_response_stream(response)` for CLI tools, or iterate `.response_gen` manually to push tokens via SSE or WebSockets. The `.get_response()` method finalizes the streamed text into a plain `Response` once the generator is exhausted, useful for logging the complete output post-stream.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, SimpleDirectoryReader

docs = SimpleDirectoryReader("./data").load_data()
index = VectorStoreIndex.from_documents(docs)

# Enable streaming at query engine level
query_engine = index.as_query_engine(streaming=True)

streaming_response = query_engine.query("Explain RAFT fine-tuning")

# Stream tokens to stdout as they arrive
for token in streaming_response.response_gen:
    print(token, end="", flush=True)

# Finalize into a full Response object for logging
final = streaming_response.get_response()
print(f"\nTotal tokens used: {final.metadata}")$escape$,
  $escape$python$escape$,
