INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5e585f04-f321-4609-8477-4573b0b03858',
  '00000000-0000-0000-0000-000000000001',
  $escape$LlamaIndex Cost Management — Token Counting, Caching, Batching, and Model Selection$escape$,
  $escape$LlamaIndex's `TokenCountingHandler` gives you per-query visibility into LLM and embedding spend before your bill does. Attach it via `Settings.callback_manager` and it tracks `total_llm_token_count` and `total_embedding_token_count` across every pipeline stage — retrieval, synthesis, and reranking separately.

For caching, `IngestionPipeline` with a `SimpleDocumentStore` (or `RedisDocumentStore` for persistence) skips re-embedding unchanged documents — critical when reindexing on a schedule. Pair it with `IngestionCache` to persist hashes across restarts and avoid redundant embedding calls entirely.

Batching is controlled via `Settings.embed_model.embed_batch_size` (OpenAI default: 10). Bumping it to 100 cuts API round-trips significantly on large corpora without increasing per-token cost.

Model selection is the highest-leverage control. Set `Settings.llm = OpenAI(model="gpt-4o-mini")` globally for retrieval and synthesis, then override at the query engine level with `llm=OpenAI(model="gpt-4o")` only for high-stakes queries. Use `MockLLM` in tests so CI pipelines burn zero tokens. These four levers together make cost a first-class observable, not an afterthought.$escape$,
  $escape$from llama_index.core import Settings, VectorStoreIndex, SimpleDirectoryReader
from llama_index.core.callbacks import CallbackManager, TokenCountingHandler
from llama_index.llms.openai import OpenAI
import tiktoken

tokenizer = tiktoken.encoding_for_model("gpt-4o-mini")
token_counter = TokenCountingHandler(tokenizer=tokenizer.encode, verbose=False)
Settings.callback_manager = CallbackManager([token_counter])
Settings.llm = OpenAI(model="gpt-4o-mini", max_tokens=512)
Settings.embed_model.embed_batch_size = 100

index = VectorStoreIndex.from_documents(SimpleDirectoryReader("./data").load_data())
response = index.as_query_engine().query("Explain RAG pipelines")

print(f"LLM tokens: {token_counter.total_llm_token_count}")
print(f"Embed tokens: {token_counter.total_embedding_token_count}")$escape$,
  $escape$python$escape$,
