INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '69661f32-614c-4302-9102-bf32b2ced9ea',
  '00000000-0000-0000-0000-000000000001',
  $escape$LlamaIndex SentenceWindowNodeParser — Precision Retrieval Without Losing Surrounding Context$escape$,
  $escape$LlamaIndex's default chunking via `SentenceSplitter` retrieves isolated fragments — fine for short docs, brittle for dense technical content. The `SentenceWindowNodeParser` solves this by embedding small sentences for high-precision matching, but storing a configurable surrounding window of sentences in node metadata. At query time, `MetadataReplacementPostProcessor` swaps the retrieved sentence back out for its full window before the LLM sees it — giving you pinpoint retrieval with broad context synthesis.

Set `window_size=3` to capture 3 sentences on each side of the match. Pair with `SentenceSplitter` as a fallback for nodes that don't benefit from windowing. For extremely long documents, chain a `SummaryIndex` over a `VectorStoreIndex`: use vector search to shortlist nodes, then summarize the top-k with `response_mode='tree_summarize'`. This avoids stuffing 100k tokens into the context window while still maintaining coherence across document sections. The `Settings.chunk_size` global controls token budget per node across all parsers.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, Settings
from llama_index.core.node_parser import SentenceWindowNodeParser
from llama_index.core.postprocessor import MetadataReplacementPostProcessor

Settings.chunk_size = 512

node_parser = SentenceWindowNodeParser.from_defaults(
    window_size=3,
    window_metadata_key="window",
    original_text_metadata_key="original_text",
)

index = VectorStoreIndex.from_documents(
    documents, transformations=[node_parser]
)

query_engine = index.as_query_engine(
    node_postprocessors=[
        MetadataReplacementPostProcessor(target_metadata_key="window")
    ],
    similarity_top_k=4,
)

response = query_engine.query("How does gradient checkpointing reduce memory?")
print(response)$escape$,
  $escape$python$escape$,
